  const es = new EventSource(`${apiUrl}/stream`);

  es.onmessage = (e) => {
    const data = JSON.parse(e.data);
    updateState(data);
  };

  es.onerror = () => {
    es.close();
    setTimeout(reconnect, 2000);
  };

  return () => es.close();
}, [apiUrl]);
